import { motion } from 'framer-motion';
import { FiPlay, FiShield, FiBarChart2, FiClock } from 'react-icons/fi';

const Hero = () => {
  return (
    <section className="relative pt-24 pb-16 md:pt-32 md:pb-24 bg-gradient-to-b from-white to-gray-50 border-b border-gray-100 overflow-hidden">
      
      {/* Decorative elements */}
      <div className="absolute inset-0 opacity-5 [mask-image:radial-gradient(ellipse_at_center,black,transparent_70%)] [background-image:linear-gradient(to_right,rgba(0,0,0,0.1)_1px,transparent_1px),linear-gradient(to_bottom,rgba(0,0,0,0.1)_1px,transparent_1px)] bg-[size:40px_40px]" />
      <div className="absolute top-20 right-20 w-64 h-64 rounded-full bg-purple-500/10 blur-3xl" />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid md:grid-cols-2 gap-12 items-center">
          {/* Left column - Text content */}
          <div className="relative z-10">
            <motion.h1 
              className="text-4xl md:text-5xl font-bold leading-tight text-gray-900 mb-6"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
            >
              <span className="block">Advanced Protection Against</span>
              <span className="bg-gradient-to-r from-purple-600 to-blue-500 bg-clip-text text-transparent">
                AI-Generated Deception
              </span>
            </motion.h1>
            
            <p className="text-lg md:text-xl text-gray-600 mb-8 max-w-lg">
              Enterprise-grade deepfake detection technology trusted by governments and Fortune 500 companies.
            </p>
            
            <div className="flex flex-col sm:flex-row gap-4 mb-12">
              <motion.a
                href="/detection-demo"
                className="flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-lg font-medium shadow-lg hover:shadow-xl transition-all"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                <FiPlay /> Live Demo
              </motion.a>
              
              <a 
                href="#technology" 
                className="flex items-center justify-center gap-2 text-purple-600 hover:text-purple-700 px-6 py-3 rounded-lg font-medium border border-gray-300 hover:border-purple-300 transition-colors"
              >
                How It Works →
              </a>
            </div>

            {/* Stats grid */}
            <div className="grid grid-cols-3 gap-4 max-w-md">
              {[
                { icon: <FiShield className="text-purple-600" />, value: "99.8%", label: "Accuracy" },
                { icon: <FiClock className="text-blue-500" />, value: "0.4s", label: "Analysis" },
                { icon: <FiBarChart2 className="text-indigo-500" />, value: "10M+", label: "Checks" }
              ].map((stat, i) => (
                <div key={i} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm">
                  <div className="text-2xl font-bold text-gray-900">{stat.value}</div>
                  <div className="flex items-center mt-1 text-sm text-gray-600">
                    {stat.icon} <span className="ml-1.5">{stat.label}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
          
          {/* Right column - Visual metaphor */}
          <div className="relative">
            <div className="relative aspect-square bg-white rounded-2xl shadow-xl border border-gray-200 overflow-hidden">
              {/* Abstract AI detection visualization */}
              <div className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-purple-50 to-blue-50">
                <div className="relative w-64 h-64">
                  {/* Neural network nodes */}
                  {[...Array(5)].map((_, i) => (
                    <div 
                      key={i}
                      className="absolute rounded-full bg-gradient-to-br from-purple-100 to-blue-100 border border-white shadow-inner"
                      style={{
                        width: `${40 + i * 20}px`,
                        height: `${40 + i * 20}px`,
                        top: `${Math.random() * 50 + 25}%`,
                        left: `${Math.random() * 50 + 25}%`,
                        opacity: 0.8 - (i * 0.15)
                      }}
                    />
                  ))}
                  {/* Central shield icon */}
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="relative z-10 p-6 bg-white rounded-full shadow-lg border-8 border-purple-100">
                      <FiShield className="h-12 w-12 text-purple-600" />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
